func sky_flattenAttrs(attrs any) []any {
	var out []any
	for _, a := range sky_asList(attrs) {
		if list, ok := a.([]any); ok {
			out = append(out, list...)
		} else {
			out = append(out, a)
		}
	}
	return out
}

