func Lib_Stripe_InitStripe() any {
	return func() any {
		key := sky_call(sky_resultWithDefault(""), Os_Getenv("STRIPE_API_KEY"))
		_ = key
		Github_Com_Stripe_StripeGo_V84_SetKey(key)
		return key
	}()
}

func Lib_Stripe_ApiKey() any {
	return Lib_Stripe_InitStripe()
}

func Lib_Stripe_DomainUrl() any {
	return func() any {
		domain := sky_call(sky_resultWithDefault(""), Os_Getenv("DOMAIN"))
		_ = domain
		port_ := sky_call(sky_resultWithDefault(""), Os_Getenv("SKY_LIVE_PORT"))
		_ = port_
		return func() any {
			if sky_asBool(!sky_equal(domain, "")) {
				return domain
			}
			return func() any {
				effectivePort := func() any {
					if sky_asBool(sky_equal(port_, "")) {
						return "4000"
					}
					return port_
				}()
				_ = effectivePort
				return sky_concat("http://localhost:", effectivePort)
			}()
		}()
	}()
}

func Lib_Stripe_GetOrCreateCustomer(userId any, userName any, userEmail any) any {
	return func() any {
		iter := Github_Com_Stripe_StripeGo_V84_Customer_List(map[string]any{"email": userEmail, "limit": 1})
		_ = iter
		return func() any {
			if sky_asBool(Github_Com_Stripe_StripeGo_V84_Customer_IterNext(iter)) {
				return func() any {
					c := Github_Com_Stripe_StripeGo_V84_Customer_IterCustomer(iter)
					_ = c
					customerId := Github_Com_Stripe_StripeGo_V84_CustomerID(c)
					_ = customerId
					sky_println(sky_concat("[STRIPE] Found existing customer: ", customerId))
					return SkyOk(customerId)
				}()
			}
			return Lib_Stripe_CreateCustomer(userId, userName, userEmail)
		}()
	}()
}

func Lib_Stripe_CreateCustomer(userId any, userName any, userEmail any) any {
	return func() any {
		params := map[string]any{"email": userEmail, "name": userName, "metadata": sky_dictFromList([]any{SkyTuple2{V0: "sky_uid", V1: userId}})}
		_ = params
		return func() any {
			return func() any {
				__subject := Github_Com_Stripe_StripeGo_V84_Customer_New_(params)
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					c := sky_asSkyResult(__subject).OkValue
					_ = c
					return func() any {
						customerId := Github_Com_Stripe_StripeGo_V84_CustomerID(c)
						_ = customerId
						sky_println(sky_concat("[STRIPE] Created customer: ", customerId))
						return SkyOk(customerId)
					}()
				}
				if sky_asSkyResult(__subject).SkyName == "Err" {
					e := sky_asSkyResult(__subject).ErrValue
					_ = e
					return SkyErr(sky_concat("Failed to create Stripe customer: ", sky_errorToString(e)))
				}
				return nil
			}()
		}()
	}()
}

func Lib_Stripe_BuildLineItems(items any) any {
	return sky_call(sky_listMap(func(item any) any {
		return func() any {
			title := Lib_Db_GetField("title", item)
			_ = title
			price := Lib_Db_GetInt("price_amount", item)
			_ = price
			discount := Lib_Db_GetInt("price_discount", item)
			_ = discount
			effectivePrice := func() any {
				if sky_asBool(sky_asInt(sky_asInt(price)-sky_asInt(discount)) > sky_asInt(0)) {
					return sky_asInt(price) - sky_asInt(discount)
				}
				return price
			}()
			_ = effectivePrice
			qty := Lib_Db_GetInt("quantity", item)
			_ = qty
			currency := sky_stringToLower(Lib_Db_GetField("price_currency", item))
			_ = currency
			return map[string]any{"price_data": map[string]any{"product_data": map[string]any{"name": title}, "unit_amount": effectivePrice, "currency": currency}, "quantity": qty}
		}()
	}), items)
}

