func Lib_Stripe_DeductStock(orderId any) any {
	return func() any {
		orderItems := sky_call(sky_resultWithDefault([]any{}), Lib_Db_QueryWhere("order_items", "order_id", "==", orderId))
		_ = orderItems
		items := func() any {
			if sky_asBool(sky_listIsEmpty(orderItems)) {
				return sky_call(sky_resultWithDefault([]any{}), Lib_Db_QueryWhere("cart_items", "cart_id", "==", orderId))
			}
			return orderItems
		}()
		_ = items
		sky_call(sky_listMap(Lib_Stripe_DeductItemStock), items)
		sky_println(sky_concat("[STOCK] Deducted for order: ", orderId))
		return struct{}{}
	}()
}

func Lib_Stripe_DeductItemStock(item any) any {
	return func() any {
		productId := Lib_Db_GetField("product_id", item)
		_ = productId
		qty := Lib_Db_GetInt("quantity", item)
		_ = qty
		return func() any {
			return func() any {
				__subject := Lib_Db_GetDoc("products", productId)
				if sky_asSkyResult(__subject).SkyName == "Ok" && sky_asSkyMaybe(sky_asSkyResult(__subject).OkValue).SkyName == "Just" {
					product := sky_asSkyMaybe(sky_asSkyResult(__subject).OkValue).JustValue
					_ = product
					return func() any {
						currentStock := Lib_Db_GetInt("stock", product)
						_ = currentStock
						return func() any {
							if sky_asBool(sky_asInt(currentStock) >= sky_asInt(0)) {
								return func() any {
									newStock := func() any {
										if sky_asBool(sky_asInt(sky_asInt(currentStock)-sky_asInt(qty)) >= sky_asInt(0)) {
											return sky_asInt(currentStock) - sky_asInt(qty)
										}
										return 0
									}()
									_ = newStock
									updatedProduct := sky_call2(sky_dictInsert("stock"), Lib_Db_IntVal(newStock), product)
									_ = updatedProduct
									Lib_Db_SetDoc("products", productId, updatedProduct)
									return struct{}{}
								}()
							}
							return struct{}{}
						}()
					}()
				}
				if true {
					return struct{}{}
				}
				return nil
			}()
		}()
	}()
}

