func Lib_Products_SortProducts(sortBy any, sortDir any, products any) any {
	return func() any {
		sorted := func() any {
			if sky_asBool(sky_equal(sortBy, "price")) {
				return sky_call(sky_listSortBy(func(p any) any {
					return sky_asInt(Lib_Db_GetInt("price_amount", p)) - sky_asInt(Lib_Db_GetInt("price_discount", p))
				}), products)
			}
			if sky_asBool(sky_equal(sortBy, "title")) {
				return sky_call(sky_listSortBy(func(_ any) any { return 0 }), products)
			}
			return products
		}()
		_ = sorted
		return func() any {
			if sky_asBool(sky_equal(sortDir, "desc")) {
				return sky_listReverse(sorted)
			}
			return sorted
		}()
	}()
}

