func Lib_Auth_FindOrCreateUser(uid any, email any, name any) any {
	return func() any {
		isAdminUser := sky_call(sky_listMember(email), Lib_Auth_AdminEmails())
		_ = isAdminUser
		adminStr := func() any {
			if sky_asBool(isAdminUser) {
				return "true"
			}
			return "false"
		}()
		_ = adminStr
		upsertData := sky_dictFromList([]any{SkyTuple2{V0: "id", V1: uid}, SkyTuple2{V0: "firebase_uid", V1: uid}, SkyTuple2{V0: "email", V1: email}, SkyTuple2{V0: "name", V1: name}, SkyTuple2{V0: "is_admin", V1: Lib_Db_BoolVal(isAdminUser)}})
		_ = upsertData
		Lib_Db_SetDoc("users", uid, upsertData)
		result := Lib_Db_GetDoc("users", uid)
		_ = result
		return func() any {
			return func() any {
				__subject := result
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					maybeUser := sky_asSkyResult(__subject).OkValue
					_ = maybeUser
					return func() any {
						return func() any {
							__subject := maybeUser
							if sky_asSkyMaybe(__subject).SkyName == "Just" {
								user := sky_asSkyMaybe(__subject).JustValue
								_ = user
								return func() any {
									if sky_asBool(Lib_Db_GetBool("suspended", user)) {
										return SkyErr("Account suspended. Please contact support.")
									}
									return func() any {
										sky_println(sky_concat("[AUTH] Signed in: ", sky_concat(email, sky_concat(" (admin: ", sky_concat(adminStr, ")")))))
										return SkyOk(user)
									}()
								}()
							}
							if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
								return SkyErr("Failed to load user profile.")
							}
							if sky_asSkyResult(__subject).SkyName == "Err" {
								e := sky_asSkyResult(__subject).ErrValue
								_ = e
								return SkyErr(e)
							}
							return nil
						}()
					}()
				}
				return nil
			}()
		}()
	}()
}

