func Lib_Cart_AddItem(cartId any, productId any, quantity any) any {
	return func() any {
		existingItems := sky_call(sky_resultWithDefault([]any{}), Lib_Db_QueryWhere("cart_items", "cart_id", "==", cartId))
		_ = existingItems
		matchingItems := sky_call(sky_listFilter(func(item any) any { return sky_equal(Lib_Db_GetField("product_id", item), productId) }), existingItems)
		_ = matchingItems
		return func() any {
			return func() any {
				__subject := sky_listHead(matchingItems)
				if sky_asSkyMaybe(__subject).SkyName == "Just" {
					existing := sky_asSkyMaybe(__subject).JustValue
					_ = existing
					return func() any {
						existingQty := Lib_Db_GetInt("quantity", existing)
						_ = existingQty
						newQty := sky_asInt(existingQty) + sky_asInt(quantity)
						_ = newQty
						itemId := Lib_Db_GetField("id", existing)
						_ = itemId
						updatedItem := sky_call2(sky_dictInsert("quantity"), Lib_Db_IntVal(newQty), existing)
						_ = updatedItem
						Lib_Db_SetDoc("cart_items", itemId, updatedItem)
						Lib_Cart_RecalculateTotal(cartId)
						return SkyOk(struct{}{})
					}()
				}
				if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
					return func() any {
						itemId := sky_call(sky_resultWithDefault(""), Github_Com_Google_Uuid_NewString(struct{}{}))
						_ = itemId
						itemData := sky_dictFromList([]any{SkyTuple2{V0: "id", V1: itemId}, SkyTuple2{V0: "cart_id", V1: cartId}, SkyTuple2{V0: "product_id", V1: productId}, SkyTuple2{V0: "quantity", V1: Lib_Db_IntVal(quantity)}})
						_ = itemData
						Lib_Db_SetDoc("cart_items", itemId, itemData)
						Lib_Cart_RecalculateTotal(cartId)
						return SkyOk(struct{}{})
					}()
				}
				return nil
			}()
		}()
	}()
}

