func Lib_Cart_CheckoutToOrder(cartId any) any {
	return func() any {
		orderId := sky_call(sky_resultWithDefault(""), Github_Com_Google_Uuid_NewString(struct{}{}))
		_ = orderId
		return func() any {
			return func() any {
				__subject := Lib_Db_GetDoc("carts", cartId)
				if sky_asSkyResult(__subject).SkyName == "Ok" && sky_asSkyMaybe(sky_asSkyResult(__subject).OkValue).SkyName == "Just" {
					cart := sky_asSkyMaybe(sky_asSkyResult(__subject).OkValue).JustValue
					_ = cart
					return func() any {
						orderData := sky_call2(sky_dictInsert("id"), orderId, sky_call2(sky_dictInsert("cart_id"), cartId, cart))
						_ = orderData
						Lib_Db_SetDoc("orders", orderId, orderData)
						cartItems := sky_call(sky_resultWithDefault([]any{}), Lib_Db_QueryWhere("cart_items", "cart_id", "==", cartId))
						_ = cartItems
						sky_call(sky_listMap(func(item any) any {
							return func() any {
								itemId := sky_call(sky_resultWithDefault(""), Github_Com_Google_Uuid_NewString(struct{}{}))
								_ = itemId
								enriched := Lib_Cart_EnrichCartItem(item)
								_ = enriched
								orderItem := sky_call2(sky_dictInsert("id"), itemId, sky_call2(sky_dictInsert("order_id"), orderId, sky_call2(sky_dictInsert("cart_id"), cartId, enriched)))
								_ = orderItem
								return Lib_Db_SetDoc("order_items", itemId, orderItem)
							}()
						}), cartItems)
						sky_println(sky_concat("[CHECKOUT] Created order ", sky_concat(orderId, sky_concat(" from cart ", cartId))))
						return SkyOk(orderId)
					}()
				}
				if true {
					return SkyErr("Cart not found.")
				}
				return nil
			}()
		}()
	}()
}

