func subscriptions(model any) any {
	return func() any {
		return func() any {
			__subject := sky_asMap(model)["page"]
			if sky_asMap(__subject)["SkyName"] == "AdminOrdersPage" {
				return sky_call(sky_timeEvery(15000), Tick)
			}
			if sky_asMap(__subject)["SkyName"] == "OrdersPage" {
				return sky_call(sky_timeEvery(30000), Tick)
			}
			if true {
				return sky_subNone()
			}
			return nil
		}()
	}()
}

func guard(msg any, model any) any {
	return func() any {
		return func() any {
			__subject := msg
			if sky_asMap(__subject)["SkyName"] == "SubmitProduct" {
				return requireAdmin(model)
			}
			if sky_asMap(__subject)["SkyName"] == "DeleteProduct" {
				return requireAdmin(model)
			}
			if sky_asMap(__subject)["SkyName"] == "UpdateOrderState" {
				return requireAdmin(model)
			}
			if sky_asMap(__subject)["SkyName"] == "UploadImage" {
				return requireAdmin(model)
			}
			if sky_asMap(__subject)["SkyName"] == "DeleteImage" {
				return requireAdmin(model)
			}
			if sky_asMap(__subject)["SkyName"] == "AddToCart" {
				return requireAuth(model)
			}
			if sky_asMap(__subject)["SkyName"] == "StartCheckout" {
				return requireAuth(model)
			}
			if sky_asMap(__subject)["SkyName"] == "UpdateRemarks" {
				return requireAuth(model)
			}
			if true {
				return SkyOk(struct{}{})
			}
			return nil
		}()
	}()
}

func requireAuth(model any) any {
	return func() any {
		return func() any {
			__subject := sky_asMap(model)["user"]
			if sky_asSkyMaybe(__subject).SkyName == "Just" {
				return SkyOk(struct{}{})
			}
			if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
				return SkyErr("Authentication required")
			}
			return nil
		}()
	}()
}

func requireAdmin(model any) any {
	return func() any {
		return func() any {
			__subject := sky_asMap(model)["user"]
			if sky_asSkyMaybe(__subject).SkyName == "Just" {
				user := sky_asSkyMaybe(__subject).JustValue
				_ = user
				return func() any {
					if sky_asBool(Lib_Auth_IsAdmin(user)) {
						return SkyOk(struct{}{})
					}
					return SkyErr("Admin access required")
				}()
			}
			if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
				return SkyErr("Authentication required")
			}
			return nil
		}()
	}()
}

